item.aggregated_output:
package codex

import (
	"encoding/json"
	"fmt"
	"slices"
	"strings"

	"github.com/johnnyfreeman/viewscreen/config"
	"github.com/johnnyfreeman/viewscreen/render"
	"github.com/johnnyfreeman/viewscreen/style"
	"github.com/johnnyfreeman/viewscreen/terminal"
	"github.com/johnnyfreeman/viewscreen/textutil"
)

// maxOutputLines caps how many lines of command output are shown when not
// running verbosely, mirroring the truncation the Claude renderers apply.
const maxOutputLines = 25

// argWidth is the maximum width of a header argument (command/path) before it
// is truncated. Matches the tools header renderer.
const argWidth = 80

// Renderer turns codex events into styled terminal output. It is stateful: a
// single Renderer instance must be used for the lifetime of one stream so that
// it can deduplicate items that codex reports more than once (an item.started
// followed by an item.completed for the same id).
type Renderer struct {
	md         *render.MarkdownRenderer
	config     config.Provider
	headerSeen map[string]bool
}

// RendererOption configures a Renderer.
type RendererOption func(*Renderer)

// WithConfigProvider sets a custom config provider.
func WithConfigProvider(cp config.Provider) RendererOption {
	return func(r *Renderer) {
		r.config = cp
	}
}

// WithMarkdownRenderer sets a custom markdown renderer (used in tests).
func WithMarkdownRenderer(md *render.MarkdownRenderer) RendererOption {
	return func(r *Renderer) {
		r.md = md
	}
}

// NewRenderer creates a Renderer with default dependencies.
func NewRenderer(opts ...RendererOption) *Renderer {
	cfg := config.Get()
	r := &Renderer{
		config:     cfg,
		md:         render.NewMarkdownRenderer(cfg.NoColor(), terminal.Width()),
		headerSeen: make(map[string]bool),
	}
	for _, opt := range opts {
		opt(r)
	}
	return r
}

// SetWidth updates the word-wrap width of the markdown renderer.
func (r *Renderer) SetWidth(width int) {
	r.md.SetWidth(width)
}

// Render renders a single codex event to a string. It returns "" for events
// that produce no output (e.g. turn.started, or a duplicate item).
func (r *Renderer) Render(event Event) string {
	switch event.Type {
	case TypeThreadStarted:
		return r.renderThreadStarted(event)
	case TypeTurnCompleted:
		return r.renderTurnCompleted(event)
	case TypeTurnFailed:
		return r.renderTurnFailed(event)
	case TypeError:
		return r.renderError(event.Message)
	case TypeItemStarted:
		return r.renderItem("started", event.Item)
	case TypeItemUpdated:
		return r.renderItem("updated", event.Item)
	case TypeItemCompleted:
		return r.renderItem("completed", event.Item)
	default: // turn.started and any unknown envelope
		return ""
	}
}

// once reports whether id is being seen for the first time, marking it seen.
func (r *Renderer) once(id string) bool {
	if id == "" {
		return true // unidentified items always render
	}
	if r.headerSeen[id] {
		return false
	}
	r.headerSeen[id] = true
	return true
}

func (r *Renderer) renderThreadStarted(event Event) string {
	out := render.StringOutput()
	fmt.Fprintln(out, style.BulletHeader("Codex Session"))
	if event.ThreadID != "" {
		fmt.Fprintf(out, "%s%s %s\n", style.OutputPrefix, style.MutedText("Thread:"), event.ThreadID)
	}
	fmt.Fprintln(out)
	return out.String()
}

func (r *Renderer) renderTurnCompleted(event Event) string {
	out := render.StringOutput()
	fmt.Fprintln(out)
	fmt.Fprintln(out, style.BulletSuccessHeader("Turn Complete"))
	if event.Usage != nil && r.config.ShowUsage() {
		u := event.Usage
		fmt.Fprintf(out, "%s%s in=%d out=%d (cached=%d reasoning=%d)\n",
			style.OutputPrefix, style.MutedText("Tokens:"),
			u.InputTokens, u.OutputTokens, u.CachedInputTokens, u.ReasoningOutputTokens)
	}
	return out.String()
}

func (r *Renderer) renderTurnFailed(event Event) string {
	msg := ""
	if event.Error != nil {
		msg = event.Error.Message
	}
	out := render.StringOutput()
	fmt.Fprintln(out)
	fmt.Fprintln(out, style.BulletErrorHeader("Turn Failed"))
	if msg != "" {
		fmt.Fprintf(out, "%s%s\n", style.OutputPrefix, style.ErrorText(msg))
	}
	return out.String()
}

func (r *Renderer) renderError(message string) string {
	out := render.StringOutput()
	fmt.Fprintln(out, style.BulletErrorHeader("Error"))
	if message != "" {
		fmt.Fprintf(out, "%s%s\n", style.OutputPrefix, style.ErrorText(message))
	}
	return out.String()
}

func (r *Renderer) renderItem(phase string, item *Item) string {
	if item == nil {
		return ""
	}
	switch item.Type {
	case ItemAgentMessage:
		if item.Text == "" || !r.once(item.ID) {
			return ""
		}
		return r.md.Render(item.Text)
	case ItemReasoning:
		if item.Text == "" || !r.once(item.ID) {
			return ""
		}
		return r.renderReasoning(item.Text)
	case ItemCommandExecution:
		return r.renderCommand(phase, item)
	case ItemFileChange:
		if !r.once(item.ID) {
			return ""
		}
		return r.renderFileChange(item)
	case ItemTodoList:
		if !r.once(item.ID) {
			return ""
		}
		return r.renderTodoList(item)
	case ItemMCPToolCall:
		return r.renderMCPToolCall(phase, item)
	case ItemWebSearch:
		if !r.once(item.ID) {
			return ""
		}
		return r.renderWebSearch(item)
	case ItemError:
		if !r.once(item.ID) {
			return ""
		}
		return r.renderError(firstNonEmpty(item.Message, item.Text))
	default:
		return r.renderUnknownItem(phase, item)
	}
}

func (r *Renderer) renderReasoning(text string) string {
	out := render.StringOutput()
	fmt.Fprintln(out, style.MutedText(style.Bullet+" Thinking"))
	fmt.Fprint(out, r.md.RenderMuted(text))
	return out.String()
}

// renderCommand renders a shell command. The header (the command itself) is
// printed the first time the item is seen; the output and exit status are
// printed when the item completes.
func (r *Renderer) renderCommand(phase string, item *Item) string {
	out := render.StringOutput()
	if r.once(item.ID) {
		fmt.Fprint(out, header("Shell", ShellCommand(item.Command)))
	}
	if phase == "completed" {
		r.writeCommandOutput(out, item)
	}
	return out.String()
}

func (r *Renderer) writeCommandOutput(out *render.Output, item *Item) {
	pw := textutil.NewPrefixedWriter(out, style.OutputPrefix, style.OutputContinue)
	body := strings.TrimRight(item.AggregatedOutput, "\n")
	if body != "" {
		for _, line := range r.capLines(strings.Split(body, "\n")) {
			pw.WriteLine(line)
		}
	}
	if item.ExitCode != nil && *item.ExitCode != 0 {
		pw.WriteLine(style.ErrorText(fmt.Sprintf("exited with code %d", *item.ExitCode)))
	} else if item.Status == "failed" {
		pw.WriteLine(style.ErrorText("failed"))
	} else if body == "" {
		pw.WriteLine(style.MutedText("(no output)"))
	}
}

func (r *Renderer) renderFileChange(item *Item) string {
	out := render.StringOutput()
	fmt.Fprint(out, header("Edit", FileChangeSummary(item.Changes)))
	if len(item.Changes) > 1 {
		pw := textutil.NewPrefixedWriter(out, style.OutputPrefix, style.OutputContinue)
		for _, c := range item.Changes {
			pw.WriteLinef("%s %s", changeKindLabel(c.Kind), c.Path)
		}
	}
	return out.String()
}

func (r *Renderer) renderTodoList(item *Item) string {
	out := render.StringOutput()
	fmt.Fprint(out, header("Update Todos", ""))
	pw := textutil.NewPrefixedWriter(out, style.OutputPrefix, style.OutputContinue)
	for _, todo := range item.Items {
		if todo.Completed {
			pw.WriteLinef("%s %s", style.SuccessText("✓"), style.MutedText(todo.Text))
		} else {
			pw.WriteLinef("%s %s", style.MutedText("○"), todo.Text)
		}
	}
	return out.String()
}

func (r *Renderer) renderMCPToolCall(phase string, item *Item) string {
	out := render.StringOutput()
	if r.once(item.ID) {
		fmt.Fprint(out, header(MCPLabel(item), ""))
	}
	if phase == "completed" && item.Status == "failed" {
		pw := textutil.NewPrefixedWriter(out, style.OutputPrefix, style.OutputContinue)
		pw.WriteLine(style.ErrorText("failed"))
	}
	return out.String()
}

func (r *Renderer) renderWebSearch(item *Item) string {
	return header("Web Search", item.Query)
}

func (r *Renderer) renderUnknownItem(phase string, item *Item) string {
	out := render.StringOutput()
	arg := firstNonEmpty(item.Command, item.Query, item.Status)
	if r.once(item.ID) {
		fmt.Fprint(out, header(unknownItemLabel(item.Type), arg))
	}
	if phase == "completed" || phase == "updated" {
		r.writeUnknownItemDetails(out, item, arg)
	}
	return out.String()
}

func (r *Renderer) writeUnknownItemDetails(out *render.Output, item *Item, headerArg string) {
	pw := textutil.NewPrefixedWriter(out, style.OutputPrefix, style.OutputContinue)
	detail := firstNonEmpty(item.Message, item.Text)
	if detail != "" && detail != headerArg {
		for _, line := range strings.Split(strings.TrimRight(detail, "\n"), "\n") {
			pw.WriteLine(line)
		}
	}
	if item.Status == "failed" {
		pw.WriteLine(style.ErrorText("failed"))
	}
	if r.config.IsVerbose() && len(item.Raw) > 0 {
		if compact := compactRawItem(item.Raw); compact != "" {
			pw.WriteLine(style.MutedText(compact))
		}
	}
}

// capLines truncates a slice of output lines unless verbose output is enabled.
func (r *Renderer) capLines(lines []string) []string {
	if r.config.IsVerbose() || len(lines) <= maxOutputLines {
		return lines
	}
	hidden := len(lines) - maxOutputLines
	kept := slices.Clone(lines[:maxOutputLines])
	return append(kept, style.MutedText(fmt.Sprintf("… (+%d more lines)", hidden)))
}

// header renders a tool-style header line: a gradient bullet + label, followed
// by an optional muted argument. It mirrors the layout of tools.HeaderRenderer
// so codex output is visually consistent with the Claude renderers.
func header(label, arg string) string {
	var b strings.Builder
	b.WriteString(style.ApplyThemeBoldGradient(style.Bullet + " " + label))
	if arg != "" {
		b.WriteString(" " + style.MutedText(truncate(arg, argWidth)))
	}
	b.WriteString("\n")
	return b.String()
}

// ShellCommand extracts the inner command from codex's shell invocation,
// which wraps commands as "<shell> -lc <script>". It is exported so callers
// that need the human-readable command (e.g. the live spinner label) share the
// same unwrapping the renderer uses for command headers.
func ShellCommand(cmd string) string {
	for _, sep := range []string{" -lc ", " -c "} {
		if i := strings.Index(cmd, sep); i != -1 {
			return unquote(strings.TrimSpace(cmd[i+len(sep):]))
		}
	}
	return cmd
}

func unquote(s string) string {
	if len(s) >= 2 {
		first, last := s[0], s[len(s)-1]
		if (first == '\'' && last == '\'') || (first == '"' && last == '"') {
			return s[1 : len(s)-1]
		}
	}
	return s
}

// FileChangeSummary returns the human-readable argument for a file_change item:
// the single path when only one file is touched, or "N files" otherwise. It is
// exported so the live spinner can label an in-flight file change the same way
// the inline header does (mirroring ShellCommand and MCPLabel).
func FileChangeSummary(changes []FileChange) string {
	switch len(changes) {
	case 0:
		return ""
	case 1:
		return changes[0].Path
	default:
		return fmt.Sprintf("%d files", len(changes))
	}
}

func changeKindLabel(kind string) string {
	switch kind {
	case "add":
		return style.SuccessText("add")
	case "delete":
		return style.ErrorText("delete")
	default:
		return style.WarningText("update")
	}
}

// MCPLabel returns a "server.tool" label for an mcp_tool_call item, falling
// back to whichever of server/tool is present. It is exported so the live
// spinner can label an in-flight MCP call the same way the header does.
func MCPLabel(item *Item) string {
	switch {
	case item.Server != "" && item.Tool != "":
		return item.Server + "." + item.Tool
	case item.Tool != "":
		return item.Tool
	case item.Server != "":
		return item.Server
	default:
		return "MCP Tool"
	}
}

func unknownItemLabel(itemType string) string {
	if itemType == "" {
		return "Codex Item"
	}
	parts := strings.Fields(strings.NewReplacer("_", " ", "-", " ").Replace(itemType))
	for i, part := range parts {
		parts[i] = strings.ToUpper(part[:1]) + part[1:]
	}
	return strings.Join(parts, " ")
}

func compactRawItem(raw json.RawMessage) string {
	var v any
	if err := json.Unmarshal(raw, &v); err != nil {
		return ""
	}
	b, err := json.Marshal(v)
	if err != nil {
		return ""
	}
	return string(b)
}

func truncate(s string, max int) string {
	s = strings.ReplaceAll(s, "\n", " ")
	if len(s) > max {
		return s[:max-3] + "..."
	}
	return s
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if v != "" {
			return v
		}
	}
	return ""
}

// Package codex parses and renders the JSONL event stream emitted by the
// Codex CLI ("codex exec --json").
//
// Codex's stream is structured very differently from Claude Code's
// stream-json: instead of message events carrying content blocks, Codex emits
// a flat sequence of envelope events (thread.*, turn.*, item.*) where each
// "item" is a self-contained unit of work (an agent message, a shell command,
// a file change, etc.). This package models that schema and renders it using
// the shared style/render helpers so Codex output looks at home alongside the
// Claude renderers.
package codex

import (
	"encoding/json"
	"strings"
)

// Envelope event types emitted by codex exec --json.
const (
	TypeThreadStarted = "thread.started"
	TypeTurnStarted   = "turn.started"
	TypeTurnCompleted = "turn.completed"
	TypeTurnFailed    = "turn.failed"
	TypeItemStarted   = "item.started"
	TypeItemUpdated   = "item.updated"
	TypeItemCompleted = "item.completed"
	TypeError         = "error"
)

// Item types carried inside item.* envelope events.
const (
	ItemAgentMessage     = "agent_message"
	ItemReasoning        = "reasoning"
	ItemCommandExecution = "command_execution"
	ItemFileChange       = "file_change"
	ItemTodoList         = "todo_list"
	ItemMCPToolCall      = "mcp_tool_call"
	ItemWebSearch        = "web_search"
	ItemError            = "error"
)

// Event is a single parsed line from the codex stream. Only the fields
// relevant to the envelope's Type are populated.
type Event struct {
	Type     string       `json:"type"`
	ThreadID string       `json:"thread_id,omitempty"`
	Usage    *Usage       `json:"usage,omitempty"`
	Error    *ThreadError `json:"error,omitempty"`
	Item     *Item        `json:"item,omitempty"`
	// Message carries the text of a top-level "error" envelope.
	Message string `json:"message,omitempty"`
}

// Usage holds token accounting reported on turn.completed.
type Usage struct {
	InputTokens           int `json:"input_tokens"`
	CachedInputTokens     int `json:"cached_input_tokens"`
	OutputTokens          int `json:"output_tokens"`
	ReasoningOutputTokens int `json:"reasoning_output_tokens"`
}

// ThreadError describes a failed turn.
type ThreadError struct {
	Message string `json:"message"`
}

// Item is the union of every item shape codex emits. Fields are decoded
// leniently so unknown or partially-populated items still render sensibly.
type Item struct {
	Raw json.RawMessage `json:"-"`

	ID   string `json:"id"`
	Type string `json:"type"`

	// agent_message, reasoning, and error items.
	Text    string `json:"text,omitempty"`
	Message string `json:"message,omitempty"`

	// command_execution items.
	Command          string `json:"command,omitempty"`
	AggregatedOutput string `json:"aggregated_output,omitempty"`
	ExitCode         *int   `json:"exit_code,omitempty"`
	Status           string `json:"status,omitempty"`

	// file_change items.
	Changes []FileChange `json:"changes,omitempty"`

	// todo_list items.
	Items []TodoItem `json:"items,omitempty"`

	// mcp_tool_call items.
	Server string `json:"server,omitempty"`
	Tool   string `json:"tool,omitempty"`

	// web_search items.
	Query string `json:"query,omitempty"`
}

// FileChange is a single path touched by a file_change item.
type FileChange struct {
	Path string `json:"path"`
	Kind string `json:"kind"` // "add", "update", or "delete"
}

// TodoItem is a single entry in a todo_list item.
type TodoItem struct {
	Text      string `json:"text"`
	Completed bool   `json:"completed"`
}

// IsEventType reports whether t is a codex envelope event type. It is used to
// distinguish codex lines from Claude Code lines, which never use these known
// types or Codex's dotted envelope naming convention.
func IsEventType(t string) bool {
	switch t {
	case TypeThreadStarted, TypeTurnStarted, TypeTurnCompleted, TypeTurnFailed,
		TypeItemStarted, TypeItemUpdated, TypeItemCompleted, TypeError:
		return true
	default:
		return strings.Contains(t, ".")
	}
}

// UnmarshalJSON decodes a codex item while preserving the raw payload. Codex
// can add item types before viewscreen knows their typed fields, and keeping
// the original JSON lets the renderer still show useful detail for those
// forward-compatible fallbacks.
func (i *Item) UnmarshalJSON(data []byte) error {
	type item Item
	var decoded item
	if err := json.Unmarshal(data, &decoded); err != nil {
		return err
	}
	*i = Item(decoded)
	i.Raw = append(i.Raw[:0], data...)
	return nil
}

// ParseEvent decodes a single codex JSONL line into an Event.
func ParseEvent(line []byte) (Event, error) {
	var event Event
	if err := json.Unmarshal(line, &event); err != nil {
		return Event{}, err
	}
	return event, nil
}

package codex

import (
	"strings"
	"testing"

	"github.com/johnnyfreeman/viewscreen/render"
	"github.com/johnnyfreeman/viewscreen/style"
	"github.com/johnnyfreeman/viewscreen/testutil"
)

// newTestRenderer builds a Renderer that produces deterministic, color-free
// output suitable for substring assertions.
func newTestRenderer(t *testing.T, showUsage, verbose bool) *Renderer {
	t.Helper()
	style.Init(true)
	t.Cleanup(func() { style.Init(false) })

	level := 0
	if verbose {
		level = 1
	}
	cfg := testutil.MockConfigProvider{NoColorVal: true, ShowUsageVal: showUsage, VerboseLevelVal: level}
	return NewRenderer(
		WithConfigProvider(cfg),
		WithMarkdownRenderer(render.NewMarkdownRenderer(true, 80)),
	)
}

func itemEvent(phase string, item Item) Event {
	return Event{Type: phase, Item: &item}
}

func intPtr(n int) *int { return &n }

func TestRender_ThreadStarted(t *testing.T) {
	r := newTestRenderer(t, true, false)
	out := r.Render(Event{Type: TypeThreadStarted, ThreadID: "abc123"})
	if !strings.Contains(out, "Codex Session") {
		t.Errorf("missing header in %q", out)
	}
	if !strings.Contains(out, "abc123") {
		t.Errorf("missing thread id in %q", out)
	}
}

func TestRender_TurnStartedIsSilent(t *testing.T) {
	r := newTestRenderer(t, true, false)
	if out := r.Render(Event{Type: TypeTurnStarted}); out != "" {
		t.Errorf("turn.started should render nothing, got %q", out)
	}
}

func TestRender_AgentMessage(t *testing.T) {
	r := newTestRenderer(t, true, false)
	out := r.Render(itemEvent(TypeItemCompleted, Item{ID: "m1", Type: ItemAgentMessage, Text: "hello there"}))
	if !strings.Contains(out, "hello there") {
		t.Errorf("missing message text in %q", out)
	}
}

func TestRender_AgentMessageDedup(t *testing.T) {
	r := newTestRenderer(t, true, false)
	first := r.Render(itemEvent(TypeItemCompleted, Item{ID: "m1", Type: ItemAgentMessage, Text: "hello"}))
	second := r.Render(itemEvent(TypeItemCompleted, Item{ID: "m1", Type: ItemAgentMessage, Text: "hello"}))
	if first == "" {
		t.Fatal("first render should produce output")
	}
	if second != "" {
		t.Errorf("duplicate message should render nothing, got %q", second)
	}
}

func TestRender_Reasoning(t *testing.T) {
	r := newTestRenderer(t, true, false)
	out := r.Render(itemEvent(TypeItemCompleted, Item{ID: "r1", Type: ItemReasoning, Text: "weighing options"}))
	if !strings.Contains(out, "Thinking") {
		t.Errorf("missing Thinking header in %q", out)
	}
	if !strings.Contains(out, "weighing options") {
		t.Errorf("missing reasoning text in %q", out)
	}
}

func TestRender_CommandHeaderThenOutput(t *testing.T) {
	r := newTestRenderer(t, true, false)
	item := Item{ID: "c1", Type: ItemCommandExecution, Command: "/usr/bin/zsh -lc ls", AggregatedOutput: "foo.txt\n", ExitCode: intPtr(0), Status: "completed"}

	started := r.Render(itemEvent(TypeItemStarted, item))
	if !strings.Contains(started, "Shell") || !strings.Contains(started, "ls") {
		t.Errorf("started should show command header, got %q", started)
	}
	if strings.Contains(started, "foo.txt") {
		t.Errorf("started should not include output, got %q", started)
	}

	completed := r.Render(itemEvent(TypeItemCompleted, item))
	if strings.Contains(completed, "Shell") {
		t.Errorf("completed should not repeat the header, got %q", completed)
	}
	if !strings.Contains(completed, "foo.txt") {
		t.Errorf("completed should include output, got %q", completed)
	}
}

func TestRender_CommandCompletedOnly(t *testing.T) {
	r := newTestRenderer(t, true, false)
	item := Item{ID: "c1", Type: ItemCommandExecution, Command: "/bin/bash -c 'echo hi'", AggregatedOutput: "hi\n", ExitCode: intPtr(0), Status: "completed"}
	out := r.Render(itemEvent(TypeItemCompleted, item))
	if !strings.Contains(out, "Shell") || !strings.Contains(out, "echo hi") {
		t.Errorf("expected header with unwrapped command, got %q", out)
	}
	if !strings.Contains(out, "hi") {
		t.Errorf("expected output, got %q", out)
	}
}

func TestRender_CommandNonZeroExit(t *testing.T) {
	r := newTestRenderer(t, true, false)
	item := Item{ID: "c1", Type: ItemCommandExecution, Command: "/bin/sh -lc false", AggregatedOutput: "", ExitCode: intPtr(2), Status: "completed"}
	out := r.Render(itemEvent(TypeItemCompleted, item))
	if !strings.Contains(out, "exited with code 2") {
		t.Errorf("expected exit code note, got %q", out)
	}
}

func TestRender_CommandNoOutput(t *testing.T) {
	r := newTestRenderer(t, true, false)
	item := Item{ID: "c1", Type: ItemCommandExecution, Command: "/bin/sh -lc true", AggregatedOutput: "", ExitCode: intPtr(0), Status: "completed"}
	out := r.Render(itemEvent(TypeItemCompleted, item))
	if !strings.Contains(out, "(no output)") {
		t.Errorf("expected (no output), got %q", out)
	}
}

func TestRender_CommandOutputTruncation(t *testing.T) {
	var lines []string
	for range maxOutputLines + 10 {
		lines = append(lines, "line")
	}
	output := strings.Join(lines, "\n") + "\n"
	item := Item{ID: "c1", Type: ItemCommandExecution, Command: "/bin/sh -lc cat", AggregatedOutput: output, ExitCode: intPtr(0), Status: "completed"}

	t.Run("non-verbose truncates", func(t *testing.T) {
		r := newTestRenderer(t, true, false)
		out := r.Render(itemEvent(TypeItemCompleted, item))
		if !strings.Contains(out, "more lines") {
			t.Errorf("expected truncation note, got %q", out)
		}
	})

	t.Run("verbose keeps all", func(t *testing.T) {
		r := newTestRenderer(t, true, true)
		out := r.Render(itemEvent(TypeItemCompleted, item))
		if strings.Contains(out, "more lines") {
			t.Errorf("verbose should not truncate, got %q", out)
		}
	})
}

func TestRender_FileChangeSingle(t *testing.T) {
	r := newTestRenderer(t, true, false)
