import (
	"github.com/johnnyfreeman/viewscreen/assistant"
	"github.com/johnnyfreeman/viewscreen/codex"
	"github.com/johnnyfreeman/viewscreen/result"
	"github.com/johnnyfreeman/viewscreen/stream"
	"github.com/johnnyfreeman/viewscreen/system"
	"github.com/johnnyfreeman/viewscreen/tools"
	"github.com/johnnyfreeman/viewscreen/user"
)

// RendererSet holds the complete set of renderers needed to process events.
// This consolidates the renderer initialization that was previously duplicated
// between the parser and TUI packages.
type RendererSet struct {
	System       *system.Renderer
	Assistant    *assistant.Renderer
	User         *user.Renderer
	Result       *result.Renderer
	Stream       *stream.Renderer
	PendingTools *tools.ToolUseTracker
	Codex        *codex.Renderer
}

// NewRendererSet creates a new RendererSet with default renderers.
func NewRendererSet() *RendererSet {
	return &RendererSet{
		System:       system.NewRenderer(),
		Assistant:    assistant.NewRenderer(),
		User:         user.NewRenderer(),
		Result:       result.NewRenderer(),
		Stream:       stream.NewRenderer(),
		PendingTools: tools.NewToolUseTracker(),
		Codex:        codex.NewRenderer(),
	}
}

// SetWidth updates the word-wrap width for all markdown renderers.
// This is called when the viewport resizes.
func (rs *RendererSet) SetWidth(width int) {
	rs.Stream.SetWidth(width)
	rs.Assistant.SetWidth(width)
	rs.Codex.SetWidth(width)
}

// Package events provides unified event parsing.
package events

import (
	"encoding/json"

	"github.com/johnnyfreeman/viewscreen/assistant"
	"github.com/johnnyfreeman/viewscreen/codex"
	"github.com/johnnyfreeman/viewscreen/result"
	"github.com/johnnyfreeman/viewscreen/stream"
	"github.com/johnnyfreeman/viewscreen/system"
	"github.com/johnnyfreeman/viewscreen/types"
	"github.com/johnnyfreeman/viewscreen/user"
)

// re-export event types for convenience
type (
	AssistantEventData = assistant.Event
	UserEventData      = user.Event
	StreamEventData    = stream.Event
	SystemEventData    = system.Event
	ResultEventData    = result.Event
)

// Event represents a parsed event of any type.
type Event interface {
	eventMarker()
}

// SystemEvent wraps a parsed system event.
type SystemEvent struct{ Data system.Event }

func (SystemEvent) eventMarker() {}

// SubAgentSystemEvent wraps a system event emitted by a subagent.
// These have ParentToolUseID set and typically carry empty session fields.
type SubAgentSystemEvent struct{ Data system.Event }

func (SubAgentSystemEvent) eventMarker() {}

// AssistantEvent wraps a parsed assistant event.
type AssistantEvent struct{ Data assistant.Event }

func (AssistantEvent) eventMarker() {}

// UserEvent wraps a parsed user event.
type UserEvent struct{ Data user.Event }

func (UserEvent) eventMarker() {}

// StreamEvent wraps a parsed stream event.
type StreamEvent struct{ Data stream.Event }

func (StreamEvent) eventMarker() {}

// ResultEvent wraps a parsed result event.
type ResultEvent struct{ Data result.Event }

func (ResultEvent) eventMarker() {}

// CodexEvent wraps a parsed event from the Codex CLI stream (codex exec --json).
// Codex uses an entirely separate set of envelope types from Claude Code, so it
// is modeled as a distinct event rather than mapped onto the Claude events.
type CodexEvent struct{ Data codex.Event }

func (CodexEvent) eventMarker() {}

// IgnoredEvent wraps an event type that is recognized but intentionally not processed.
// Examples: rate_limit_event.
type IgnoredEvent struct{ Type string }

func (IgnoredEvent) eventMarker() {}

// ParseError represents an error parsing an event.
type ParseError struct {
	Err  error
	Line string
}

func (ParseError) eventMarker() {}

// Parse parses a JSON line into a typed Event.
// Returns nil for empty lines.
func Parse(line string) Event {
	if line == "" {
		return nil
	}

	var base types.BaseEvent
	if err := json.Unmarshal([]byte(line), &base); err != nil {
		return ParseError{Err: err, Line: line}
	}

	switch base.Type {
	case "system":
		var event system.Event
		if err := json.Unmarshal([]byte(line), &event); err != nil {
			return ParseError{Err: err, Line: line}
		}
		if event.ParentToolUseID != nil {
			return SubAgentSystemEvent{Data: event}
		}
		return SystemEvent{Data: event}

	case "assistant":
		var event assistant.Event
		if err := json.Unmarshal([]byte(line), &event); err != nil {
			return ParseError{Err: err, Line: line}
		}
		return AssistantEvent{Data: event}

	case "user":
		var event user.Event
		if err := json.Unmarshal([]byte(line), &event); err != nil {
			return ParseError{Err: err, Line: line}
		}
		return UserEvent{Data: event}

	case "stream_event":
		var event stream.Event
		if err := json.Unmarshal([]byte(line), &event); err != nil {
			return ParseError{Err: err, Line: line}
		}
		return StreamEvent{Data: event}

	case "result":
		var event result.Event
		if err := json.Unmarshal([]byte(line), &event); err != nil {
			return ParseError{Err: err, Line: line}
		}
		return ResultEvent{Data: event}

	case "rate_limit_event":
		return IgnoredEvent{Type: base.Type}

	default:
		if codex.IsEventType(base.Type) {
			event, err := codex.ParseEvent([]byte(line))
			if err != nil {
				return ParseError{Err: err, Line: line}
			}
			return CodexEvent{Data: event}
		}
		return ParseError{Err: nil, Line: "Unknown event type: " + base.Type}
	}
}

